namespace SiteInspector.Client.Models;

public class Site
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string Name { get; set; } = string.Empty;
    public string Address { get; set; } = string.Empty;
}

namespace SiteInspector.Client.Models;

public enum InspectionStatus
{
    InProgress,
    Completed,
    Synced
}

public class Inspection
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string SiteId { get; set; } = string.Empty;
    public string InspectorName { get; set; } = string.Empty;
    public DateTime StartedAt { get; set; } = DateTime.UtcNow;
    public DateTime? CompletedAt { get; set; }
    public string Notes { get; set; } = string.Empty;
    public InspectionStatus Status { get; set; } = InspectionStatus.InProgress;
}

namespace SiteInspector.Client.Models;

public enum ComplianceStatus
{
    NotChecked,
    Yes,
    No,
    NA
}

public class ChecklistItem
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string InspectionId { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public ComplianceStatus IsCompliant { get; set; } = ComplianceStatus.NotChecked;
    public string Notes { get; set; } = string.Empty;
}

namespace SiteInspector.Client.Models;

public class Photo
{
    public string Id { get; set; } = Guid.NewGuid().ToString();
    public string InspectionId { get; set; } = string.Empty;
    public string? ChecklistItemId { get; set; }
    public string FileName { get; set; } = string.Empty;
    public string Base64Data { get; set; } = string.Empty;
    public DateTime CapturedAt { get; set; } = DateTime.UtcNow;
}

namespace SiteInspector.Client.Models;

public static class ChecklistTemplate
{
    public static readonly Dictionary<string, string[]> Categories = new()
    {
        ["Fall Protection"] = new[]
        {
            "Guardrails in place",
            "Safety nets installed",
            "Harnesses available",
            "Floor openings covered"
        },
        ["Scaffolding"] = new[]
        {
            "Base plates secured",
            "Planking in good condition",
            "Guardrails installed",
            "Access ladders provided"
        },
        ["Electrical"] = new[]
        {
            "GFCI protection in use",
            "Cords in good condition",
            "Panels accessible",
            "Lockout/tagout procedures"
        },
        ["PPE"] = new[]
        {
            "Hard hats worn",
            "Safety glasses worn",
            "High-vis vests worn",
            "Proper footwear"
        },
        ["Housekeeping"] = new[]
        {
            "Walkways clear",
            "Materials stored properly",
            "Waste containers available",
            "No tripping hazards"
        },
        ["Fire Safety"] = new[]
        {
            "Extinguishers accessible",
            "Hot work permits posted",
            "Flammable storage proper",
            "Emergency exits clear"
        }
    };

    public static List<ChecklistItem> CreateItemsForInspection(string inspectionId)
    {
        var items = new List<ChecklistItem>();
        foreach (var (category, descriptions) in Categories)
        {
            foreach (var description in descriptions)
            {
                items.Add(new ChecklistItem
                {
                    InspectionId = inspectionId,
                    Category = category,
                    Description = description
                });
            }
        }
        return items;
    }
}

