using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public interface IInspectionStore
{
    Task InitializeAsync();
    Task<List<Site>> GetSitesAsync();
    Task SaveSiteAsync(Site site);
    Task<Inspection?> GetInspectionAsync(string id);
    Task<List<Inspection>> GetAllInspectionsAsync();
    Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId);
    Task SaveInspectionAsync(Inspection inspection);
    Task<List<ChecklistItem>> GetChecklistItemsAsync(string inspectionId);
    Task SaveChecklistItemAsync(ChecklistItem item);
    Task SaveChecklistItemsAsync(List<ChecklistItem> items);
    Task<List<Photo>> GetPhotosAsync(string inspectionId);
    Task<List<Photo>> GetPhotosByItemAsync(string checklistItemId);
    Task SavePhotoAsync(Photo photo);
    Task DeletePhotoAsync(string id);
    Task<List<Inspection>> GetUnsyncedInspectionsAsync();
    Task MarkAsSyncedAsync(string inspectionId);
}

using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class IndexedDbStore : IInspectionStore
{
    private readonly IJSRuntime _js;
    private bool _initialized;

    public IndexedDbStore(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        if (_initialized) return;
        await _js.InvokeVoidAsync("indexedDb.open");
        _initialized = true;
    }

    public async Task<List<Site>> GetSitesAsync()
    {
        await InitializeAsync();
        return await GetAllRecords<Site>("sites");
    }

    public async Task SaveSiteAsync(Site site)
    {
        await InitializeAsync();
        await PutRecord("sites", site.Id, site);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        await InitializeAsync();
        return await GetRecord<Inspection>("inspections", id);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        await InitializeAsync();
        return await GetAllRecords<Inspection>("inspections");
    }

    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
    {
        var all = await GetAllInspectionsAsync();
        return all.Where(i => i.SiteId == siteId).ToList();
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        await InitializeAsync();
        await PutRecord("inspections", inspection.Id, inspection);
    }

    public async Task<List<ChecklistItem>> GetChecklistItemsAsync(string inspectionId)
    {
        await InitializeAsync();
        var all = await GetAllRecords<ChecklistItem>("checklistItems");
        return all.Where(i => i.InspectionId == inspectionId).ToList();
    }

    public async Task SaveChecklistItemAsync(ChecklistItem item)
    {
        await InitializeAsync();
        await PutRecord("checklistItems", item.Id, item);
    }

    public async Task SaveChecklistItemsAsync(List<ChecklistItem> items)
    {
        await InitializeAsync();
        foreach (var item in items)
        {
            await PutRecord("checklistItems", item.Id, item);
        }
    }

    public async Task<List<Photo>> GetPhotosAsync(string inspectionId)
    {
        await InitializeAsync();
