    {
        if (_status.IsSyncing) return;

        _status.IsSyncing = true;
        _status.LastSyncAttempt = DateTime.UtcNow;
        _status.LastSyncError = null;
        OnStatusChanged?.Invoke();

        try
        {
            var unsynced = await _store.GetUnsyncedInspectionsAsync();
            _status.PendingCount = unsynced.Count;

