            {
                var items = await _store.GetChecklistItemsAsync(inspection.Id);
                var photos = await _store.GetPhotosAsync(inspection.Id);

                var payload = new
                {
                    Inspection = inspection,
                    ChecklistItems = items,
                    Photos = photos
                };

                var response = await _http.PostAsJsonAsync("/api/inspections/sync", payload);
                if (response.IsSuccessStatusCode)
                {
                    await _store.MarkAsSyncedAsync(inspection.Id);
                    _status.PendingCount--;
                    OnStatusChanged?.Invoke();
                }
            }
        }
        catch (Exception ex)
        {
            _status.LastSyncError = ex.Message;
        }
        finally
        {
            _status.IsSyncing = false;
            OnStatusChanged?.Invoke();
        }
    }

