+        _timer = new Timer(async _ =>
+        {
+            if (_connectivity.IsOnline && !_status.IsSyncing)
+            {
+                await SyncNowAsync();
+            }
+        }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(30));
+    }
+
+    public void StopBackgroundSync()
+    {
+        _timer?.Dispose();
+        _timer = null;
+    }
+
+    private async void OnConnectivityChanged(bool isOnline)
+    {
+        _status.IsOnline = isOnline;
+        OnStatusChanged?.Invoke();
+        if (isOnline)
+        {
+            await SyncNowAsync();
+        }
+    }
+
+    public void Dispose()
+    {
+        _timer?.Dispose();
+        _connectivity.OnConnectivityChanged -= OnConnectivityChanged;
+    }
+}
