@page "/"
@inject IInspectionStore Store
@inject NavigationManager Nav

<div class="page-title">Sites</div>

@if (_sites == null)
{
    <p>Loading...</p>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <div class="icon">🏗️</div>
        <p>No sites yet. Add your first construction site.</p>
    </div>
}
else
{
    @foreach (var site in _sites)
    {
        <div class="card" @onclick="() => StartInspection(site.Id)">
            <h3>@site.Name</h3>
            <p>@site.Address</p>
        </div>
    }
}

<button class="btn btn-primary btn-block" @onclick="ShowAddSite" style="margin-top:16px;">+ Add Site</button>

@if (_showAddSite)
{
    <div class="card" style="margin-top:12px;">
        <div class="form-group">
            <label>Site Name</label>
            <input class="form-control" @bind="_newSiteName" placeholder="e.g. Tower Block A" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input class="form-control" @bind="_newSiteAddress" placeholder="123 Main St" />
        </div>
        <button class="btn btn-success btn-block" @onclick="AddSite">Save Site</button>
    </div>
}

@code {
    private List<Site>? _sites;
    private bool _showAddSite;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _sites = await Store.GetSitesAsync();

        if (_sites.Count == 0)
        {
            // Seed some default sites
            var defaults = new[]
            {
                new Site { Name = "Tower Block A", Address = "100 Construction Ave" },
                new Site { Name = "Warehouse Expansion", Address = "50 Industrial Rd" },
                new Site { Name = "Bridge Deck Repairs", Address = "Highway 7 Overpass" }
            };
            foreach (var s in defaults) await Store.SaveSiteAsync(s);
            _sites = await Store.GetSitesAsync();
        }
    }

    private void StartInspection(string siteId) => Nav.NavigateTo($"/new-inspection/{siteId}");

    private void ShowAddSite() => _showAddSite = true;

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Site { Name = _newSiteName, Address = _newSiteAddress };
        await Store.SaveSiteAsync(site);
        _sites = await Store.GetSitesAsync();
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddSite = false;
    }
}

@page "/new-inspection/{SiteId}"
@inject IInspectionStore Store
@inject NavigationManager Nav

<div class="page-title">New Inspection</div>

<div class="card">
    <div class="form-group">
        <label>Site</label>
        <p style="font-weight:600;">@_siteName</p>
    </div>
    <div class="form-group">
        <label>Inspector Name</label>
        <input class="form-control" @bind="_inspectorName" placeholder="Your name" />
    </div>
    <div class="form-group">
        <label>Notes (optional)</label>
        <input class="form-control" @bind="_notes" placeholder="Weather, conditions, etc." />
    </div>
    <button class="btn btn-primary btn-block" @onclick="Start" disabled="@string.IsNullOrWhiteSpace(_inspectorName)">
        Start Inspection
    </button>
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";
    private string _siteName = "Loading...";
    private string _inspectorName = "";
    private string _notes = "";

    protected override async Task OnInitializedAsync()
    {
        var sites = await Store.GetSitesAsync();
        var site = sites.FirstOrDefault(s => s.Id == SiteId);
        _siteName = site?.Name ?? "Unknown Site";
    }

    private async Task Start()
    {
        if (string.IsNullOrWhiteSpace(_inspectorName)) return;

        var inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = _inspectorName,
            Notes = _notes,
            StartedAt = DateTime.UtcNow,
            Status = InspectionStatus.InProgress
        };

        await Store.SaveInspectionAsync(inspection);

        var items = ChecklistTemplate.CreateItemsForInspection(inspection.Id);
        await Store.SaveChecklistItemsAsync(items);

        Nav.NavigateTo($"/checklist/{inspection.Id}");
    }
}

@page "/checklist/{InspectionId}"
@inject IInspectionStore Store
@inject NavigationManager Nav

<div class="page-title">Safety Checklist</div>

@if (_items == null)
{
    <p>Loading...</p>
}
else
{
    <div class="category-tabs">
        @foreach (var cat in _categories)
        {
            <button class="category-tab @(cat == _activeCategory ? "active" : "")"
                    @onclick="() => _activeCategory = cat">@cat</button>
        }
    </div>

    @foreach (var item in _items.Where(i => i.Category == _activeCategory))
    {
        <div class="checklist-item">
            <div class="item-description">@item.Description</div>
            <div class="compliance-group">
                <button class="compliance-btn yes @(item.IsCompliant == ComplianceStatus.Yes ? "selected" : "")"
                        @onclick="() => SetCompliance(item, ComplianceStatus.Yes)">✓ Yes</button>
                <button class="compliance-btn no @(item.IsCompliant == ComplianceStatus.No ? "selected" : "")"
                        @onclick="() => SetCompliance(item, ComplianceStatus.No)">✗ No</button>
                <button class="compliance-btn na @(item.IsCompliant == ComplianceStatus.NA ? "selected" : "")"
                        @onclick="() => SetCompliance(item, ComplianceStatus.NA)">N/A</button>
            </div>
            <div class="item-notes">
                <input placeholder="Add note..." value="@item.Notes"
                       @onchange="(e) => SetNotes(item, e.Value?.ToString() ?? "")" />
            </div>
        </div>
    }

    <div style="display:flex; gap:8px; margin-top:16px;">
        <button class="btn btn-outline" style="flex:1;" @onclick="TakePhoto">📷 Photo</button>
        <button class="btn btn-success" style="flex:1;" @onclick="Complete">Complete ✓</button>
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";
    private List<ChecklistItem>? _items;
    private string[] _categories = Array.Empty<string>();
    private string _activeCategory = "";

    protected override async Task OnInitializedAsync()
    {
        _items = await Store.GetChecklistItemsAsync(InspectionId);
        _categories = _items.Select(i => i.Category).Distinct().ToArray();
        _activeCategory = _categories.FirstOrDefault() ?? "";
    }

    private async Task SetCompliance(ChecklistItem item, ComplianceStatus status)
    {
        item.IsCompliant = status;
        await Store.SaveChecklistItemAsync(item);
    }

    private async Task SetNotes(ChecklistItem item, string notes)
    {
        item.Notes = notes;
        await Store.SaveChecklistItemAsync(item);
    }

    private void TakePhoto() => Nav.NavigateTo($"/photo/{InspectionId}");

    private async Task Complete()
    {
        var inspection = await Store.GetInspectionAsync(InspectionId);
        if (inspection != null)
        {
            inspection.Status = InspectionStatus.Completed;
            inspection.CompletedAt = DateTime.UtcNow;
            await Store.SaveInspectionAsync(inspection);
        }
        Nav.NavigateTo($"/summary/{InspectionId}");
    }
}

@page "/photo/{InspectionId}"
@page "/photo/{InspectionId}/{ChecklistItemId}"
@inject IInspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-title">Capture Photo</div>

<div class="card">
    <div class="form-group">
        <label>Take or select a photo</label>
        <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment"
                   style="min-height:48px; padding:12px 0;" />
    </div>

    @if (!string.IsNullOrEmpty(_preview))
    {
        <img src="@_preview" style="width:100%; border-radius:8px; margin-top:12px;" alt="Preview" />
        <button class="btn btn-success btn-block" style="margin-top:12px;" @onclick="SavePhoto">Save Photo</button>
    }
</div>

@if (_photos.Count > 0)
{
    <div class="page-title" style="margin-top:16px;">Captured Photos (@_photos.Count)</div>
    <div class="photo-grid">
        @foreach (var photo in _photos)
        {
            <img class="photo-thumb" src="@($"data:image/jpeg;base64,{photo.Base64Data}")" alt="@photo.FileName" />
        }
    </div>
}

<button class="btn btn-outline btn-block" style="margin-top:16px;" @onclick="GoBack">← Back to Checklist</button>

@code {
    [Parameter] public string InspectionId { get; set; } = "";
    [Parameter] public string? ChecklistItemId { get; set; }
    private string _preview = "";
    private string _base64Data = "";
    private string _fileName = "";
    private List<Photo> _photos = new();

    protected override async Task OnInitializedAsync()
    {
        _photos = await Store.GetPhotosAsync(InspectionId);
    }

    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        _fileName = file.Name;
        var buffer = new byte[file.Size];
        await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
        _base64Data = Convert.ToBase64String(buffer);
        _preview = $"data:{file.ContentType};base64,{_base64Data}";
    }

    private async Task SavePhoto()
    {
        if (string.IsNullOrEmpty(_base64Data)) return;

        var photo = new Photo
        {
            InspectionId = InspectionId,
            ChecklistItemId = ChecklistItemId,
            FileName = _fileName,
            Base64Data = _base64Data,
            CapturedAt = DateTime.UtcNow
        };

        await Store.SavePhotoAsync(photo);
        _photos = await Store.GetPhotosAsync(InspectionId);
        _preview = "";
        _base64Data = "";
    }

    private void GoBack() => Nav.NavigateTo($"/checklist/{InspectionId}");
}

@page "/summary/{InspectionId}"
@inject IInspectionStore Store
@inject NavigationManager Nav

<div class="page-title">Inspection Summary</div>

@if (_inspection == null)
{
    <p>Loading...</p>
}
else
{
    <div class="card">
        <div class="summary-stat"><span>Inspector</span><strong>@_inspection.InspectorName</strong></div>
        <div class="summary-stat"><span>Started</span><strong>@_inspection.StartedAt.ToLocalTime().ToString("g")</strong></div>
        @if (_inspection.CompletedAt.HasValue)
        {
            <div class="summary-stat"><span>Completed</span><strong>@_inspection.CompletedAt.Value.ToLocalTime().ToString("g")</strong></div>
        }
        <div class="summary-stat"><span>Status</span>
            <span class="sync-badge @(_inspection.Status == InspectionStatus.Synced ? "synced" : "pending")">
                @_inspection.Status
            </span>
        </div>
        @if (!string.IsNullOrWhiteSpace(_inspection.Notes))
        {
            <div class="summary-stat"><span>Notes</span><span>@_inspection.Notes</span></div>
        }
    </div>

