    protected override async Task OnInitializedAsync()
    {
        await Store.InitializeAsync();
        _sites = await Store.GetSitesAsync();

        if (_sites.Count == 0)
        {
            // Seed some default sites
            var defaults = new[]
            {
                new Site { Name = "Tower Block A", Address = "100 Construction Ave" },
                new Site { Name = "Warehouse Expansion", Address = "50 Industrial Rd" },
                new Site { Name = "Bridge Deck Repairs", Address = "Highway 7 Overpass" }
            };
            foreach (var s in defaults) await Store.SaveSiteAsync(s);
            _sites = await Store.GetSitesAsync();
        }
    }

    private void StartInspection(string siteId) => Nav.NavigateTo($"/new-inspection/{siteId}");

    private void ShowAddSite() => _showAddSite = true;

    private async Task AddSite()
    {
