@page "/photo/{InspectionId}/{ChecklistItemId}"
@inject IInspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-title">Capture Photo</div>

<div class="card">
    <div class="form-group">
        <label>Take or select a photo</label>
        <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment"
                   style="min-height:48px; padding:12px 0;" />
    </div>

    @if (!string.IsNullOrEmpty(_preview))
    {
        <img src="@_preview" style="width:100%; border-radius:8px; margin-top:12px;" alt="Preview" />
        <button class="btn btn-success btn-block" style="margin-top:12px;" @onclick="SavePhoto">Save Photo</button>
    }
</div>

@if (_photos.Count > 0)
{
    <div class="page-title" style="margin-top:16px;">Captured Photos (@_photos.Count)</div>
    <div class="photo-grid">
        @foreach (var photo in _photos)
        {
            <img class="photo-thumb" src="@($"data:image/jpeg;base64,{photo.Base64Data}")" alt="@photo.FileName" />
        }
    </div>
}

<button class="btn btn-outline btn-block" style="margin-top:16px;" @onclick="GoBack">← Back to Checklist</button>

@code {
    [Parameter] public string InspectionId { get; set; } = "";
    [Parameter] public string? ChecklistItemId { get; set; }
    private string _preview = "";
    private string _base64Data = "";
    private string _fileName = "";
    private List<Photo> _photos = new();

    protected override async Task OnInitializedAsync()
    {
        _photos = await Store.GetPhotosAsync(InspectionId);
    }

    private async Task HandleFileSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file == null) return;

        _fileName = file.Name;
        var buffer = new byte[file.Size];
        await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
        _base64Data = Convert.ToBase64String(buffer);
        _preview = $"data:{file.ContentType};base64,{_base64Data}";
    }

    private async Task SavePhoto()
    {
        if (string.IsNullOrEmpty(_base64Data)) return;

        var photo = new Photo
        {
            InspectionId = InspectionId,
            ChecklistItemId = ChecklistItemId,
            FileName = _fileName,
            Base64Data = _base64Data,
            CapturedAt = DateTime.UtcNow
        };

        await Store.SavePhotoAsync(photo);
        _photos = await Store.GetPhotosAsync(InspectionId);
        _preview = "";
        _base64Data = "";
    }

    private void GoBack() => Nav.NavigateTo($"/checklist/{InspectionId}");
}

