+            InspectorName = _inspectorName,
+            Notes = _notes,
+            StartedAt = DateTime.UtcNow,
+            Status = InspectionStatus.InProgress
+        };
+
+        await Store.SaveInspectionAsync(inspection);
+
+        var items = ChecklistTemplate.CreateItemsForInspection(inspection.Id);
