+    @if (!string.IsNullOrEmpty(_preview))
+    {
+        <img src="@_preview" style="width:100%; border-radius:8px; margin-top:12px;" alt="Preview" />
+        <button class="btn btn-success btn-block" style="margin-top:12px;" @onclick="SavePhoto">Save Photo</button>
