+    private List<Inspection> _inspections = new();
+    private int _pendingCount;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _status = await Sync.GetStatusAsync();
+        _inspections = await Store.GetAllInspectionsAsync();
+        _pendingCount = _inspections.Count(i => i.Status == InspectionStatus.Completed);
+        Sync.OnStatusChanged += HandleStatusChanged;
+    }
+
+    private async void HandleStatusChanged()
+    {
+        _status = await Sync.GetStatusAsync();
+        _inspections = await Store.GetAllInspectionsAsync();
+        _pendingCount = _inspections.Count(i => i.Status == InspectionStatus.Completed);
+        await InvokeAsync(StateHasChanged);
+    }
