using System.Collections.Concurrent;
using SiteInspector.Client.Models;

namespace SiteInspector.Services;

public class InspectionRepository
{
    private readonly ConcurrentDictionary<string, Site> _sites = new();
    private readonly ConcurrentDictionary<string, Inspection> _inspections = new();
    private readonly ConcurrentDictionary<string, ChecklistItem> _checklistItems = new();
    private readonly ConcurrentDictionary<string, Photo> _photos = new();

    public InspectionRepository()
    {
        // Seed default sites
        var sites = new[]
        {
            new Site { Id = "site-1", Name = "Tower Block A", Address = "100 Construction Ave" },
            new Site { Id = "site-2", Name = "Warehouse Expansion", Address = "50 Industrial Rd" },
            new Site { Id = "site-3", Name = "Bridge Deck Repairs", Address = "Highway 7 Overpass" }
        };
        foreach (var s in sites) _sites[s.Id] = s;
    }

    public IEnumerable<Site> GetSites() => _sites.Values;
    public IEnumerable<Inspection> GetInspections() => _inspections.Values;

    public void SyncInspection(Inspection inspection, List<ChecklistItem> items, List<Photo> photos)
    {
        inspection.Status = InspectionStatus.Synced;
        _inspections[inspection.Id] = inspection;
        foreach (var item in items) _checklistItems[item.Id] = item;
        foreach (var photo in photos) _photos[photo.Id] = photo;
    }
}

