using SiteInspector.Client.Models;
using SiteInspector.Client.Pages;
using SiteInspector.Components;
using SiteInspector.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveWebAssemblyComponents();
builder.Services.AddSingleton<InspectionRepository>();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

// API Endpoints
app.MapGet("/api/sites", (InspectionRepository repo) => Results.Ok(repo.GetSites()));

app.MapGet("/api/inspections", (InspectionRepository repo) => Results.Ok(repo.GetInspections()));

app.MapPost("/api/inspections/sync", (InspectionSyncPayload payload, InspectionRepository repo) =>
{
    repo.SyncInspection(payload.Inspection, payload.ChecklistItems, payload.Photos);
    return Results.Ok();
});

app.Run();

public record InspectionSyncPayload(Inspection Inspection, List<ChecklistItem> ChecklistItems, List<Photo> Photos);

using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using SiteInspector.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<ConnectivityService>();
builder.Services.AddScoped<IInspectionStore, IndexedDbStore>();
builder.Services.AddScoped<ISyncService, SyncService>();

var host = builder.Build();

// Initialize connectivity monitoring
var connectivity = host.Services.GetRequiredService<ConnectivityService>();
await connectivity.InitializeAsync();

// Start background sync
var sync = host.Services.GetRequiredService<ISyncService>();
sync.StartBackgroundSync();

await host.RunAsync();

