﻿@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject NavigationManager Nav

<div class="page">
    <header class="app-header">
        <h1>🏗️ Site Inspector</h1>
        <div class="status-bar">
            <span class="connectivity-dot @(Connectivity.IsOnline ? "online" : "offline")"></span>
        </div>
    </header>

    <main class="main-content">
        @Body
    </main>

    <nav class="bottom-nav">
        <a href="/" class="@NavClass("/")">
            <span class="nav-icon">🏠</span>Sites
        </a>
        <a href="/sync" class="@NavClass("/sync")">
            <span class="nav-icon">🔄</span>Sync
        </a>
    </nav>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private string NavClass(string path)
    {
        var relativePath = Nav.ToBaseRelativePath(Nav.Uri);
        if (path == "/" && relativePath == "") return "active";
        if (path != "/" && ("/" + relativePath).StartsWith(path)) return "active";
        return "";
    }
}

